args.ReplacementContent:
"/* Theme Customizer + Page Builder Tabs & Page Items styling */
.customizer-tabs {
  display: flex;
  border-bottom: 1px solid rgba(0,0,0,0.08);
  background: #fdfdfd;
}
.customizer-tab {
  flex: 1;
  padding: 12px 6px;
  font-size: 13px;
  font-weight: 700;
  color: var(--platform-muted);
  border: none;
  background: transparent;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  transition: all 0.2s;
}
.customizer-tab.active {
  color: var(--platform-accent, #6366f1);
  border-bottom-color: var(--platform-accent, #6366f1);
  background: #f9f9fb;
}
.customizer-tab svg, .customizer-tab i {
  width: 14px;
  height: 14px;
}
.page-item-row:hover {
  border-color: var(--platform-accent, #6366f1) !important;
  background: #f9f9fb !important;
}
.page-item-row.active-page {
  border-color: var(--platform-accent, #6366f1) !important;
  background: #f5f3ff !important;
  color: var(--platform-accent, #6366f1) !important;
}

/* Theme customizer */"
